 private static function finite(array $p):bool{return isset($p['x'],$p['y'])&&is_finite($p['x'])&&is_finite($p['y']);}private static function clamp(float $v,float $a,float $b):float{return is_finite($v)?min($b,max($a,$v)):$a;}private static function dist(array$a,array$b):float{return sqrt(($b['x']-$a['x'])**2+($b['y']-$a['y'])**2);}private static function fmt(float$v):string{$v=round($v,2);if($v==0)return'0';return rtrim(rtrim(number_format($v,2,'.',''),'0'),'.');}private static function fp(array$p):string{return self::fmt($p['x']).' '.self::fmt($p['y']);}private static function along(array$a,array$b,float$d):array{$l=self::dist($a,$b);if($l==0)return$a;$t=min(1,$d/$l);return['x'=>$a['x']+($b['x']-$a['x'])*$t,'y'=>$a['y']+($b['y']-$a['y'])*$t];}private static function turn(array$a,array$b,array$c):float{$ux=$b['x']-$a['x'];$uy=$b['y']-$a['y'];$vx=$c['x']-$b['x'];$vy=$c['y']-$b['y'];$ul=sqrt($ux*$ux+$uy*$uy);$vl=sqrt($vx*$vx+$vy*$vy);return!$ul||!$vl?0:rad2deg(acos(self::clamp(($ux*$vx+$uy*$vy)/($ul*$vl),-1,1)));}
 public static function buildRoundedDrawingPath(array$input,float$fs=40):string{$p=array_values(array_filter($input,[self::class,'finite']));if(!$p)return'';if(count($p)==1)return'M '.self::fp($p[0]);$out=['M '.self::fp($p[0])];$radius=max(12,$fs*1.25);for($i=1;$i<count($p)-1;$i++){$d=min($radius,self::dist($p[$i-1],$p[$i])*0.45,self::dist($p[$i],$p[$i+1])*0.45);$out[]='L '.self::fp(self::along($p[$i],$p[$i-1],$d)).' Q '.self::fp($p[$i]).' '.self::fp(self::along($p[$i],$p[$i+1],$d));}$out[]='L '.self::fp($p[count($p)-1]);return implode(' ',$out);}
 public static function createDrawingPath(array$p,float$fs=40):array{return self::finite($p)?['points'=>[$p],'d'=>'M '.self::fp($p),'fontSize'=>$fs]:['points'=>[],'d'=>'','fontSize'=>$fs];}public static function appendDrawingPoint(array$path,array$p):array{$points=$path['points'];if(!self::finite($p)||!$points||self::dist($points[count($points)-1],$p)<3)return$path;if(count($points)==1||self::turn($points[count($points)-2],$points[count($points)-1],$p)>=18)$points[]=$p;else$points[count($points)-1]=$p;return['points'=>$points,'d'=>self::buildRoundedDrawingPath($points,$path['fontSize']),'fontSize'=>$path['fontSize']];}private static function drawing(array$points,float$fs):?array{$path=null;foreach($points as$p)if(self::finite($p))$path=$path?self::appendDrawingPoint($path,$p):self::createDrawingPath($p,$fs);return$path&&count($path['points'])>=2?$path:null;}
 private static function perp(array$p,array$a,array$b):float{$dx=$b['x']-$a['x'];$dy=$b['y']-$a['y'];$l=$dx*$dx+$dy*$dy;if(!$l)return self::dist($p,$a);$t=self::clamp((($p['x']-$a['x'])*$dx+($p['y']-$a['y'])*$dy)/$l,0,1);return self::dist($p,['x'=>$a['x']+$t*$dx,'y'=>$a['y']+$t*$dy]);}private static function simplify(array$p,float$tol):array{if(count($p)<=2)return$p;$keep=array_fill(0,count($p),false);$keep[0]=$keep[count($p)-1]=true;$stack=[[0,count($p)-1]];while($stack){[$first,$last]=array_pop($stack);$best=0;$index=-1;for($i=$first+1;$i<$last;$i++){$d=self::perp($p[$i],$p[$first],$p[$last]);if($d>$best){$best=$d;$index=$i;}}if($best>$tol){$keep[$index]=true;$stack[]=[$first,$index];$stack[]=[$index,$last];}}return array_values(array_filter($p,fn($_,$i)=>$keep[$i],ARRAY_FILTER_USE_BOTH));}
 public static function prepareArcLengthPath(array$input,float$minimum=0.5):array{$valid=array_values(array_filter($input,[self::class,'finite']));$filtered=[];foreach($valid as$p)if(!$filtered||self::dist($filtered[count($filtered)-1],$p)>=$minimum)$filtered[]=$p;if($valid&&$filtered&&self::dist($filtered[count($filtered)-1],$valid[count($valid)-1])>0)$filtered[]=$valid[count($valid)-1];$p=self::simplify($filtered,max($minimum*0.5,0.1));$segments=[];$total=0;for($i=1;$i<count($p);$i++){$l=self::dist($p[$i-1],$p[$i]);if($l>0){$segments[]=['a'=>$p[$i-1],'b'=>$p[$i],'start'=>$total,'length'=>$l];$total+=$l;}}return['points'=>$p,'segments'=>$segments,'totalLength'=>$total];}private static function pointAt(array$path,float$d):array{if(!$path['segments'])return['x'=>0,'y'=>0];$d=self::clamp($d,0,$path['totalLength']);foreach($path['segments']as$s)if($d<=$s['start']+$s['length']){$t=self::clamp(($d-$s['start'])/$s['length'],0,1);return['x'=>$s['a']['x']+($s['b']['x']-$s['a']['x'])*$t,'y'=>$s['a']['y']+($s['b']['y']-$s['a']['y'])*$t];}return$path['segments'][count($path['segments'])-1]['b'];}public static function sampleAt(array$path,float$progress,float$fs=40):array{$progress=self::clamp($progress,0,1);if($path['totalLength']<=0)return['x'=>0,'y'=>0,'angle'=>0,'progress'=>$progress];$d=$path['totalLength']*$progress;$w=max(min(max($fs*1.1,0.75),$path['totalLength']*0.06),0.75);$a=self::pointAt($path,$d-$w);$b=self::pointAt($path,$d+$w);$p=self::pointAt($path,$d);return['x'=>$p['x'],'y'=>$p['y'],'angle'=>atan2($b['y']-$a['y'],$b['x']-$a['x']),'progress'=>$progress];}
 public static function stableRepeatedText(string$text,float$fs):string{$p=trim($text);if($p==='')return'';$chars=function_exists('mb_strlen')?mb_strlen($p,'UTF-8'):strlen($p);$count=(int)ceil(20000/max($fs,$chars*$fs*0.62));$count=min(256,max(16,$count));return implode('   ',array_fill(0,$count,$p));}private static function esc(string$v):string{return htmlspecialchars($v,ENT_QUOTES|ENT_XML1,'UTF-8');}
 public static function renderSvg(string$bytes,string$mime,float$width,float$height,array$points,string$text,array$o=[]):string{if(!in_array($mime,['image/png','image/jpeg','image/webp','image/gif','image/avif'],true))throw new InvalidArgumentException('unsupported MIME');$o+=['fontSize'=>40,'fontFamily'=>'Arial, sans-serif','fontWeight'=>'700','letterSpacing'=>null,'color'=>'#ffffff','magicGradient'=>false,'opacity'=>1,'strokeColor'=>'rgba(15,23,42,0.72)','strokeWidth'=>1.5,'shadow'=>true,'repeatText'=>true,'revealProgress'=>1];$phrase=trim($text);$fs=$o['fontSize'];$path=self::drawing($points,$fs);if($phrase===''||!$path)throw new InvalidArgumentException('text and two points required');$repeat=$o['repeatText']?self::stableRepeatedText($phrase,$fs):$phrase;$gradient=$o['magicGradient']?'<linearGradient id="brush-gradient" x1="100" y1="150" x2="900" y2="850" gradientUnits="userSpaceOnUse"><stop offset="0%" stop-color="#ec4899"/><stop offset="20%" stop-color="#f97316"/><stop offset="40%" stop-color="#facc15"/><stop offset="60%" stop-color="#10b981"/><stop offset="80%" stop-color="#3b82f6"/><stop offset="100%" stop-color="#8b5cf6"/></linearGradient>':'';$shadow=$o['shadow']?'<filter id="brush-shadow"><feDropShadow dx="0" dy="2" stdDeviation="2" flood-color="#0f172a" flood-opacity="0.65"/></filter>':'';$filter=$o['shadow']?' filter="url(#brush-shadow)"':'';$fill=$o['magicGradient']?'url(#brush-gradient)':self::esc($o['color']);$spacing=$o['letterSpacing']??max(0.75,$fs*0.06);$reveal=self::clamp($o['revealProgress'],0,1);$d=self::esc($path['d']);return'<?xml version="1.0" encoding="UTF-8"?>'."\n".'<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="'.self::fmt($width).'" height="'.self::fmt($height).'" viewBox="0 0 '.self::fmt($width).' '.self::fmt($height).'"><image width="'.self::fmt($width).'" height="'.self::fmt($height).'" preserveAspectRatio="xMidYMid slice" href="data:'.$mime.';base64,'.base64_encode($bytes).'"/><defs><path id="brush-path" d="'.$d.'"/>'.$gradient.$shadow.'<mask id="brush-reveal"><rect width="100%" height="100%" fill="black"/><path d="'.$d.'" pathLength="1" fill="none" stroke="white" stroke-width="'.self::fmt($fs*2.4).'" stroke-linecap="round" stroke-linejoin="round" stroke-dasharray="1" stroke-dashoffset="'.self::fmt(1-$reveal).'"/></mask></defs><g mask="url(#brush-reveal)" opacity="'.self::fmt(self::clamp($o['opacity'],0,1)).'"'.$filter.'><text font-family="'.self::esc($o['fontFamily']).'" font-size="'.self::fmt($fs).'" font-weight="'.self::esc((string)$o['fontWeight']).'" letter-spacing="'.self::fmt($spacing).'" fill="'.$fill.'" stroke="'.self::esc($o['strokeColor']).'" stroke-width="'.self::fmt(max(0,$o['strokeWidth'])).'" paint-order="stroke fill"><textPath href="#brush-path" xlink:href="#brush-path" startOffset="0" spacing="exact">'.self::esc($repeat).'</textPath></text></g></svg>'."\n";}
